DarkRPUI=DarkRPUI or {}; DarkRPUI.Scoreboard=DarkRPUI.Scoreboard or {}; DarkRPUI.Scoreboard.ActionIds={"bring","goto","returnply","freeze","unfreeze","spectate","unspectate","stripweapons","respawn","slay","kick","warn","ban","jail","unjail","setjob","setmoney","noclip","god","cloak"}
function DarkRPUI.Scoreboard.PlayerMenu(ply) local m=DermaMenu(); m:AddOption("Copy SteamID",function() SetClipboardText(ply:SteamID()) end); if DarkRPUI.Util.IsAdmin(LocalPlayer()) then m:AddSpacer(); for _,a in ipairs(DarkRPUI.Scoreboard.ActionIds) do m:AddOption(a,function() DarkRPUI.Admin.Send(a,ply) end) end end; DarkRPUI.UI.StyleDermaMenu(m); m:Open() end
